@st.cache_resource
def load_data():
    import json
    d = json.loads(RAW_DATA)
    models = {}
    for gse, v in d.items():
        probes = v["top30"]
        # Build X matrix from embedded samples
        c0_rows = [list(v["samples_c0"][p]) for p in probes]
        c1_rows = [list(v["samples_c1"][p]) for p in probes]
        # Transpose: rows = samples, cols = probes
        X_c0 = np.array(c0_rows).T  # (n_c0, 30)
        X_c1 = np.array(c1_rows).T  # (n_c1, 30)
        X = np.vstack([X_c0, X_c1])
        y = np.array([0]*v["n_c0"] + [1]*v["n_c1"])
        sc = StandardScaler()
        Xs = sc.fit_transform(X)
        rf = RandomForestClassifier(n_estimators=300, random_state=42)
        rf.fit(Xs, y)
        imp = pd.Series(rf.feature_importances_, index=probes).sort_values(ascending=False)
        pca = PCA(n_components=min(2, Xs.shape[0]-1))
        Xpca = pca.fit_transform(Xs)
        models[gse] = {
            **v,
            "probes": probes,
            "model": rf,
            "scaler": sc,
            "importance": imp,
            "X": X, "Xs": Xs, "y": y, "Xpca": Xpca,
            "mean_c0_arr": np.array([v["mean_c0"][p] for p in probes]),
            "mean_c1_arr": np.array([v["mean_c1"][p] for p in probes]),
        }
    return models

