                sample = base + np.random.normal(0, noise*base.std(), len(base))
                Xs = ds["scaler"].transform(sample.reshape(1,-1))
                proba = ds["model"].predict_proba(Xs)[0]
                pred = int(np.argmax(proba))
                st.session_state["res"] = {
                    "pred": pred, "proba": proba,
                    "pred_name": ds["c0_name"] if pred==0 else ds["c1_name"],
                    "correct": pred==tgt, "tgt_name": demo_cls,
                }

